import{_ as o,c as d,o as i,a1 as t,j as e,a,t as n}from"./chunks/framework.DILC4Csi.js";const m=JSON.parse('{"title":"介紹: OpenCode Agent Skills | opencode-agent-skills","description":"學習 OpenCode Agent Skills 的核心價值與主要功能。掌握動態技能發現、上下文注入、壓縮恢復等特性，支援 Claude Code 相容和自動推薦。","frontmatter":{"title":"介紹: OpenCode Agent Skills | opencode-agent-skills","sidebarTitle":"讓 AI 懂你的技能","subtitle":"介紹: OpenCode Agent Skills","description":"學習 OpenCode Agent Skills 的核心價值與主要功能。掌握動態技能發現、上下文注入、壓縮恢復等特性，支援 Claude Code 相容和自動推薦。","tags":["入門指南","外掛介紹"],"prerequisite":[],"order":1},"headers":[],"relativePath":"zh-tw/joshuadavidthomas/opencode-agent-skills/start/what-is-opencode-agent-skills/index.md","filePath":"zh-tw/joshuadavidthomas/opencode-agent-skills/start/what-is-opencode-agent-skills/index.md"}'),r={name:"zh-tw/joshuadavidthomas/opencode-agent-skills/start/what-is-opencode-agent-skills/index.md"},p={tabindex:"0"};function u(s,l,c,h,g,k){return i(),d("div",null,[l[8]||(l[8]=t(`<h1 id="什麼是-opencode-agent-skills" tabindex="-1">什麼是 OpenCode Agent Skills？ <a class="header-anchor" href="#什麼是-opencode-agent-skills" aria-label="Permalink to &quot;什麼是 OpenCode Agent Skills？&quot;">​</a></h1><h2 id="學完你能做什麼" tabindex="-1">學完你能做什麼 <a class="header-anchor" href="#學完你能做什麼" aria-label="Permalink to &quot;學完你能做什麼&quot;">​</a></h2><ul><li>了解 OpenCode Agent Skills 外掛的核心價值</li><li>掌握外掛提供的主要功能特性</li><li>理解技能如何自動發現和載入</li><li>區分本外掛與其他技能管理方案的差異</li></ul><h2 id="你現在的困境" tabindex="-1">你現在的困境 <a class="header-anchor" href="#你現在的困境" aria-label="Permalink to &quot;你現在的困境&quot;">​</a></h2><p>你可能遇到過這些情況：</p><ul><li><strong>技能分散管理困難</strong>：技能散落在專案、使用者目錄、外掛快取等多個位置，找不到合適的技能</li><li><strong>對話越長越麻煩</strong>：長時間對話後，之前載入的技能因上下文壓縮而失效</li><li><strong>相容性焦慮</strong>：擔心從 Claude Code 遷移後，現有的技能和外掛無法使用</li><li><strong>需要重複設定</strong>：每個專案都要重新設定技能，缺乏統一的技能管理機制</li></ul><p>這些問題都在影響你使用 AI 助手的效率。</p><h2 id="核心思路" tabindex="-1">核心思路 <a class="header-anchor" href="#核心思路" aria-label="Permalink to &quot;核心思路&quot;">​</a></h2><p><strong>OpenCode Agent Skills</strong> 是一個為 OpenCode 提供動態技能發現和管理能力的外掛系統。</p><div class="info custom-block"><p class="custom-block-title">什麼是技能？</p><p>技能（Skill）是包含 AI 工作流程指導的可複用模組。它通常是一個目錄，包含 <code>SKILL.md</code> 檔案（描述技能的功能和使用方法），以及可能的輔助檔案（文件、指令碼等）。</p></div><p><strong>核心價值</strong>：透過標準化技能格式（SKILL.md），實現跨專案、跨對話的技能複用。</p><h3 id="技術架構" tabindex="-1">技術架構 <a class="header-anchor" href="#技術架構" aria-label="Permalink to &quot;技術架構&quot;">​</a></h3><p>外掛基於 TypeScript + Bun + Zod 開發，提供 4 個核心工具：</p><table tabindex="0"><thead><tr><th>工具</th><th>功能</th></tr></thead><tbody><tr><td><code>use_skill</code></td><td>將技能的 SKILL.md 內容注入到對話上下文</td></tr><tr><td><code>read_skill_file</code></td><td>讀取技能目錄下的支援檔案（文件、設定等）</td></tr><tr><td><code>run_skill_script</code></td><td>在技能目錄上下文中執行可執行指令碼</td></tr><tr><td><code>get_available_skills</code></td><td>取得目前可用的技能清單</td></tr></tbody></table><h2 id="主要功能特性" tabindex="-1">主要功能特性 <a class="header-anchor" href="#主要功能特性" aria-label="Permalink to &quot;主要功能特性&quot;">​</a></h2><h3 id="_1-動態技能發現" tabindex="-1">1. 動態技能發現 <a class="header-anchor" href="#_1-動態技能發現" aria-label="Permalink to &quot;1. 動態技能發現&quot;">​</a></h3><p>外掛會從多個位置自動發現技能，按優先順序排序：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. .opencode/skills/              (專案級 - OpenCode)</span></span>
<span class="line"><span>2. .claude/skills/                (專案級 - Claude Code)</span></span>
<span class="line"><span>3. ~/.config/opencode/skills/     (使用者級 - OpenCode)</span></span>
<span class="line"><span>4. ~/.claude/skills/              (使用者級 - Claude Code)</span></span>
<span class="line"><span>5. ~/.claude/plugins/cache/        (外掛快取)</span></span>
<span class="line"><span>6. ~/.claude/plugins/marketplaces/ (已安裝外掛)</span></span></code></pre></div><p><strong>規則</strong>：第一個匹配的技能生效，後續同名技能被忽略。</p><blockquote><p>為什麼這樣設計？</p><p>專案級技能優先於使用者級技能，這樣你可以在專案中自訂特定行為，而不會影響全域設定。</p></blockquote><h3 id="_2-上下文注入" tabindex="-1">2. 上下文注入 <a class="header-anchor" href="#_2-上下文注入" aria-label="Permalink to &quot;2. 上下文注入&quot;">​</a></h3><p>當你呼叫 <code>use_skill</code> 時，技能內容以 XML 格式注入到對話上下文：</p><ul><li><code>noReply: true</code> - AI 不會對注入的訊息做出回應</li><li><code>synthetic: true</code> - 標記為系統產生的訊息（不在 UI 顯示，不計入使用者輸入）</li></ul><p>這意味著技能內容會持久存在於對話上下文中，即使對話增長並發生上下文壓縮，技能仍然可用。</p><h3 id="_3-壓縮恢復機制" tabindex="-1">3. 壓縮恢復機制 <a class="header-anchor" href="#_3-壓縮恢復機制" aria-label="Permalink to &quot;3. 壓縮恢復機制&quot;">​</a></h3><p>當 OpenCode 執行上下文壓縮時（長時間對話常見操作），外掛會監聽 <code>session.compacted</code> 事件，自動重新注入可用技能清單。</p><p>這確保了 AI 在長時間對話中始終知道有哪些技能可用，不會因為壓縮而遺失技能存取能力。</p><h3 id="_4-claude-code-相容" tabindex="-1">4. Claude Code 相容 <a class="header-anchor" href="#_4-claude-code-相容" aria-label="Permalink to &quot;4. Claude Code 相容&quot;">​</a></h3><p>外掛完全相容 Claude Code 的技能和外掛系統，支援：</p><ul><li>Claude Code 技能（<code>.claude/skills/&lt;skill-name&gt;/SKILL.md</code>）</li><li>Claude 外掛快取（<code>~/.claude/plugins/cache/...</code>）</li><li>Claude 外掛市場（<code>~/.claude/plugins/marketplaces/...</code>）</li></ul><p>這意味著如果你之前使用 Claude Code，遷移到 OpenCode 後仍然可以使用現有的技能和外掛。</p><h3 id="_5-自動技能推薦" tabindex="-1">5. 自動技能推薦 <a class="header-anchor" href="#_5-自動技能推薦" aria-label="Permalink to &quot;5. 自動技能推薦&quot;">​</a></h3><p>外掛會監控你的訊息，使用語意相似度檢測是否與某個可用技能相關：</p><ul><li>計算訊息的 embedding 向量</li><li>與所有技能的描述計算餘弦相似度</li><li>當相似度超過閾值時，注入評估提示建議 AI 載入相關技能</li></ul><p>這個過程完全自動，你不需要記住技能名稱或明確請求。</p><h3 id="_6-superpowers-整合-可選" tabindex="-1">6. Superpowers 整合（可選） <a class="header-anchor" href="#_6-superpowers-整合-可選" aria-label="Permalink to &quot;6. Superpowers 整合（可選）&quot;">​</a></h3><p>外掛支援 Superpowers 工作流程，透過環境變數啟用：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">OPENCODE_AGENT_SKILLS_SUPERPOWERS_MODE</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">true</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> opencode</span></span></code></pre></div><p>啟用後，外掛會自動檢測 <code>using-superpowers</code> 技能，並在對話初始化時注入完整的工作流程指導。</p><h2 id="與其他方案對比" tabindex="-1">與其他方案對比 <a class="header-anchor" href="#與其他方案對比" aria-label="Permalink to &quot;與其他方案對比&quot;">​</a></h2>`,40)),e("table",p,[l[7]||(l[7]=e("thead",null,[e("tr",null,[e("th",null,"方案"),e("th",null,"特點"),e("th",null,"適用場景")])],-1)),e("tbody",null,[l[4]||(l[4]=e("tr",null,[e("td",null,[e("strong",null,"opencode-agent-skills")]),e("td",null,"動態發現、壓縮恢復、自動推薦"),e("td",null,"需要統一管理和自動推薦的場景")],-1)),e("tr",null,[l[2]||(l[2]=e("td",null,[e("strong",null,"opencode-skills")],-1)),e("td",null,[l[0]||(l[0]=a("自動註冊為 ",-1)),e("code",null,"skills_"+n(s.name),1),l[1]||(l[1]=a(" 工具",-1))]),l[3]||(l[3]=e("td",null,"需要獨立工具呼叫的場景",-1))]),l[5]||(l[5]=e("tr",null,[e("td",null,[e("strong",null,"superpowers")]),e("td",null,"完整軟體開發工作流程"),e("td",null,"需要嚴格流程規範的專案")],-1)),l[6]||(l[6]=e("tr",null,[e("td",null,[e("strong",null,"skillz")]),e("td",null,"MCP 伺服器模式"),e("td",null,"需要跨工具使用技能的場景")],-1))])]),l[9]||(l[9]=t('<p>選擇本外掛的理由：</p><ul><li>✅ <strong>零設定</strong>：自動發現和管理技能</li><li>✅ <strong>智慧推薦</strong>：基於語意匹配自動推薦相關技能</li><li>✅ <strong>壓縮恢復</strong>：長時間對話穩定可靠</li><li>✅ <strong>相容性</strong>：無縫遷移 Claude Code 技能</li></ul><h2 id="本課小結" tabindex="-1">本課小結 <a class="header-anchor" href="#本課小結" aria-label="Permalink to &quot;本課小結&quot;">​</a></h2><p>OpenCode Agent Skills 外掛透過動態發現、上下文注入、壓縮恢復等核心機制，為 OpenCode 提供了完整的技能管理能力。它的核心價值在於：</p><ul><li><strong>自動化</strong>：減少手動設定和記憶技能名稱的負擔</li><li><strong>穩定性</strong>：長時間對話中技能始終可用</li><li><strong>相容性</strong>：與現有 Claude Code 生態無縫整合</li></ul><h2 id="下一課預告" tabindex="-1">下一課預告 <a class="header-anchor" href="#下一課預告" aria-label="Permalink to &quot;下一課預告&quot;">​</a></h2><blockquote><p>下一課我們學習 <strong><a href="./../installation/">安裝 OpenCode Agent Skills</a></strong>。</p><p>你會學到：</p><ul><li>如何在 OpenCode 設定中新增外掛</li><li>如何驗證外掛是否正確安裝</li><li>本機開發模式的設定方法</li></ul></blockquote><hr><h2 id="附錄-原始碼參考" tabindex="-1">附錄：原始碼參考 <a class="header-anchor" href="#附錄-原始碼參考" aria-label="Permalink to &quot;附錄：原始碼參考&quot;">​</a></h2><details><summary><strong>點擊展開查看原始碼位置</strong></summary><blockquote><p>更新時間：2026-01-24</p></blockquote><table tabindex="0"><thead><tr><th>功能</th><th>檔案路徑</th><th>行號</th></tr></thead><tbody><tr><td>外掛入口和功能概述</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/src/plugin.ts#L1-L12" target="_blank" rel="noreferrer"><code>src/plugin.ts</code></a></td><td>1-12</td></tr><tr><td>核心功能特性清單</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/README.md#L5-L11" target="_blank" rel="noreferrer"><code>README.md</code></a></td><td>5-11</td></tr><tr><td>技能發現優先順序</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/src/skills.ts#L241-L246" target="_blank" rel="noreferrer"><code>src/skills.ts</code></a></td><td>241-246</td></tr><tr><td>合成訊息注入</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/src/utils.ts#L147-L162" target="_blank" rel="noreferrer"><code>src/utils.ts</code></a></td><td>147-162</td></tr><tr><td>壓縮恢復機制</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/src/plugin.ts#L144-L151" target="_blank" rel="noreferrer"><code>src/plugin.ts</code></a></td><td>144-151</td></tr><tr><td>語意匹配模組</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/src/embeddings.ts#L108-L135" target="_blank" rel="noreferrer"><code>src/embeddings.ts</code></a></td><td>108-135</td></tr></tbody></table><p><strong>關鍵常數</strong>：</p><ul><li><code>EMBEDDING_MODEL = &quot;Xenova/all-MiniLM-L6-v2&quot;</code>：使用的 embedding 模型</li><li><code>SIMILARITY_THRESHOLD = 0.35</code>：語意相似度閾值</li><li><code>TOP_K = 5</code>：自動推薦回傳的技能數量上限</li></ul><p><strong>關鍵函式</strong>：</p><ul><li><code>discoverAllSkills()</code>：從多個位置發現技能</li><li><code>use_skill()</code>：將技能內容注入到對話上下文</li><li><code>matchSkills()</code>：基於語意相似度匹配相關技能</li><li><code>injectSyntheticContent()</code>：注入合成訊息到對話</li></ul></details>',10))])}const C=o(r,[["render",u]]);export{m as __pageData,C as default};
